import threading
from collections import deque
from typing import Optional
import socket

class ConnectionPool:
    def __init__(self, host: str, port: int, max_size: int = 20):
        self.host = host
        self.port = port
        self.max_size = max_size
        self.pool: deque = deque()
        self.in_use: list = []
        self.lock = threading.Lock()
        self._available = threading.Condition(self.lock)

    def acquire(self) -> socket.socket:
        with self._available:
            while True:
                if self.pool:
                    conn = self.pool.popleft()
                    self.in_use.append(conn)
                    return conn
                if len(self.in_use) < self.max_size:
                    conn = self._create_connection()
                    self.in_use.append(conn)
                    return conn
                # At max capacity, wait for a release
                self._available.wait()

    def release(self, conn: socket.socket):
        with self._available:
            if conn in self.in_use:
                self.in_use.remove(conn)
            if len(self.pool) < self.max_size:
                self.pool.append(conn)
            else:
                conn.close()
            self._available.notify()

    def _create_connection(self) -> socket.socket:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.connect((self.host, self.port))
        return sock

    @property
    def total_connections(self) -> int:
        return len(self.pool) + len(self.in_use)
